mapper.select:
SELECT COUNT(1)
FROM building_unit
WHERE building_id = #{buildingId}
  AND name = #{name}
  AND deleted = 0

  AND id != #{excludeId}

SELECT bu.id, bu.building_id, b.name AS building_name, bu.name, bu.sort_no, bu.status, bu.create_time FROM building_unit bu INNER JOIN building b ON bu.building_id = b.id AND b.deleted = 0 WHERE bu.deleted = 0
AND bu.building_id = #{buildingId}
AND bu.name LIKE CONCAT('%', #{name}, '%')
AND bu.status = #{status}
ORDER BY bu.sort_no ASC, bu.id ASC
